        cc1101_send_slowrf(cmd + 1);
        len = snprintf(out, sizeof(out), "F OK\r\n");
    } else if (cmd[0] == 'i' && cmd[1] == 's') {
        cc1101_send_it_v1(cmd + 2);
        len = snprintf(out, sizeof(out), "is OK\r\n");
