static void fs20_send_bit(int bit) {
    if (bit) {
        gpio_set_level(GPIO_GDO0, 1);
        ets_delay_us(600);
        gpio_set_level(GPIO_GDO0, 0);
        ets_delay_us(600);
    } else {
