    }
}

static void it_v1_send_bit(char bit) {
    // T = 420us
    // '0': T High, 3T Low, T High, 3T Low
    // '1': 3T High, T Low, 3T High, T Low
    // 'F': T High, 3T Low, 3T High, T Low
    if (bit == '0') {
        gpio_set_level(GPIO_GDO0, 1); ets_delay_us(420);
        gpio_set_level(GPIO_GDO0, 0); ets_delay_us(1260);
        gpio_set_level(GPIO_GDO0, 1); ets_delay_us(420);
        gpio_set_level(GPIO_GDO0, 0); ets_delay_us(1260);
    } else if (bit == '1') {
        gpio_set_level(GPIO_GDO0, 1); ets_delay_us(1260);
        gpio_set_level(GPIO_GDO0, 0); ets_delay_us(420);
        gpio_set_level(GPIO_GDO0, 1); ets_delay_us(1260);
        gpio_set_level(GPIO_GDO0, 0); ets_delay_us(420);
    } else { // 'F'
        gpio_set_level(GPIO_GDO0, 1); ets_delay_us(420);
        gpio_set_level(GPIO_GDO0, 0); ets_delay_us(1260);
        gpio_set_level(GPIO_GDO0, 1); ets_delay_us(1260);
        gpio_set_level(GPIO_GDO0, 0); ets_delay_us(420);
    }
}

void cc1101_send_it_v1(const char* data) {
    cc1101_set_tx_mode();
    vTaskDelay(pdMS_TO_TICKS(2));

    for (int repeat = 0; repeat < 6; repeat++) {
        for (int i = 0; data[i]; i++) {
            it_v1_send_bit(data[i]);
        }
        // Sync/Gap: T high, 31T low
        gpio_set_level(GPIO_GDO0, 1); ets_delay_us(420);
        gpio_set_level(GPIO_GDO0, 0); ets_delay_us(13020);
    }
    cc1101_set_rx_mode();
}

void cc1101_send_slowrf(const char* hex_data) {
    cc1101_set_tx_mode();
    vTaskDelay(pdMS_TO_TICKS(5)); // More settling

    // Multi-transmit for reliability (standard culfw behavior)
    for (int repeat = 0; repeat < 6; repeat++) { // Increased repeats
        // 1. Preamble (standard culfw uses ~12-13 '0' bits)
        for(int i=0; i<16; i++) fs20_send_bit(0); // slightly more

        // 2. Sync bit (The sync bit is a '1' in FS20 protocol spec, culfw calls it 1)
        // Actually Spec says: 12-13 zero bits, then one '1' bit as sync.
        fs20_send_bit(1); 

        // 3. Data (hex string to bits)
        int hex_len = strlen(hex_data);
        for(int i=0; i<hex_len; i+=2) {
            char h[3] = {hex_data[i], hex_data[i+1], 0};
            uint8_t b = (uint8_t)strtol(h, NULL, 16);
            int parity = 0;
            for(int j=7; j>=0; j--) {
                int bit = (b >> j) & 1;
                fs20_send_bit(bit);
                if (bit) parity++;
            }
            // FS20: ODD parity (Total bits in 9-bit group must be odd)
            fs20_send_bit((parity % 2) ? 0 : 1);
        }

        // 4. End bit (bit 0)
        fs20_send_bit(0);

        // Gap between repeats (standard FS20 is ~10ms)
        ets_delay_us(10000);
    }

    cc1101_set_rx_mode();
}

esp_err_t cc1101_write_reg(uint8_t reg, uint8_t val) {
    spi_transaction_t t = {
        .length = 16,
        .tx_data = {reg, val},
        .flags = SPI_TRANS_USE_TXDATA
    };
    return spi_device_transmit(spi, &t);
}

esp_err_t cc1101_write_burst(uint8_t reg, const uint8_t *data, size_t len) {
    uint8_t tx_data[65];
    tx_data[0] = reg | CC1101_WRITE_BURST;
    memcpy(tx_data + 1, data, len);
    spi_transaction_t t = {
        .length = (len + 1) * 8,
        .tx_buffer = tx_data,
    };
    return spi_device_transmit(spi, &t);
}

uint8_t cc1101_read_reg(uint8_t reg) {
    uint8_t tx_data[2] = {reg | CC1101_READ_SINGLE, 0x00};
    uint8_t rx_data[2] = {0, 0};
    spi_transaction_t t = {
        .length = 16,
        .tx_buffer = tx_data,
        .rx_buffer = rx_data,
    };
    spi_device_transmit(spi, &t);
    return rx_data[1];
}

esp_err_t cc1101_cmd_strobe(uint8_t cmd) {
    spi_transaction_t t = {
        .length = 8,
        .tx_data = {cmd},
        .flags = SPI_TRANS_USE_TXDATA
    };
    return spi_device_transmit(spi, &t);
}

